import { moduleMetadata } from '@storybook/angular';
import { PfStepsComponent } from './steps.component';
const meta = {
    title: 'Composants/Steps',
    component: PfStepsComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Indicateur de progression d'un workflow. Read-only par défaut ; opt-in `[clickable]=\"true\"` pour permettre le retour aux étapes complétées.",
            },
        },
    },
    decorators: [
        moduleMetadata({ imports: [PfStepsComponent] }),
        (storyFn) => {
            const story = storyFn();
            return { ...story, template: `<div style="width: 720px;">${story.template}</div>` };
        },
    ],
    render: (args) => ({
        props: args,
        template: `<pf-steps
      [steps]="steps"
      [current]="current"
      [clickable]="clickable || false"
      (stepClick)="current = $event"
    ></pf-steps>`,
    }),
};
export default meta;
const steps = [
    { title: 'Identité', description: 'Vos informations' },
    { title: 'Adresse', description: 'Justificatif de domicile' },
    { title: 'Pièces', description: 'Documents requis' },
    { title: 'Validation', description: 'Récapitulatif' },
];
export const Default = { args: { steps, current: 1 } };
export const FirstStep = { args: { steps, current: 0 } };
export const LastStep = { args: { steps, current: 3 } };
export const Clickable = {
    args: { steps, current: 2, clickable: true },
};
export const SimpleTitlesOnly = {
    args: {
        current: 1,
        steps: [{ title: 'Étape 1' }, { title: 'Étape 2' }, { title: 'Étape 3' }],
    },
};
